import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Search } from "lucide-react";
import axios from "axios";

// SVG avatar icon (igual seu padrão)
const AvatarIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 32" width="42px" height="42px">
    <path fill="none"
      d="M8.007 24.93A4.996 4.996 0 0 1 13 20h6a4.996 4.996 0 0 1 4.993 4.93a11.94 11.94 0 0 1-15.986 0M20.5 12.5A4.5 4.5 0 1 1 16 8a4.5 4.5 0 0 1 4.5 4.5"
    />
    <path fill="#0095DA"
      d="M26.749 24.93A13.99 13.99 0 1 0 2 16a13.9 13.9 0 0 0 3.251 8.93l-.02.017c.07.084.15.156.222.239c.09.103.187.2.28.3q.418.457.87.87q.14.124.28.242q.48.415.99.782c.044.03.084.069.128.1v-.012a13.9 13.9 0 0 0 16 0v.012c.044-.031.083-.07.128-.1q.51-.368.99-.782q.14-.119.28-.242q.451-.413.87-.87c.093-.1.189-.197.28-.3c.071-.083.152-.155.222-.24ZM16 8a4.5 4.5 0 1 1-4.5 4.5A4.5 4.5 0 0 1 16 8M8.007 24.93A4.996 4.996 0 0 1 13 20h6a4.996 4.996 0 0 1 4.993 4.93a11.94 11.94 0 0 1-15.986 0"
    />
  </svg>
);

const BORDER_COLORS = [
  '#e63946', '#457b9d', '#2a9d8f', '#f4a261', '#e76f51',
];

export default function Header({ onlineUsers = [] }) {
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const [showAllOnline, setShowAllOnline] = useState(false);
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const wrapperRef = useRef(null);
  const popoverRef = useRef(null);

  // Spotlight Search + busca global
  const [searchOpen, setSearchOpen] = useState(false);
  const [search, setSearch] = useState('');
  const [resultados, setResultados] = useState(null);
  const [loading, setLoading] = useState(false);
  const searchInputRef = useRef();

  // Fecha dropdowns ao clicar fora
  useEffect(() => {
    function handleClickOutside(event) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target)) setDropdownOpen(false);
      if (popoverRef.current && !popoverRef.current.contains(event.target)) setShowAllOnline(false);
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // Spotlight: foca input ao abrir
  useEffect(() => {
    if (searchOpen) {
      setSearch('');
      setResultados(null);
      setTimeout(() => searchInputRef.current?.focus(), 120);
    }
  }, [searchOpen]);

  // Busca global (debounced)
  useEffect(() => {
    if (!search) { setResultados(null); setLoading(false); return; }
    setLoading(true);
    const timeout = setTimeout(() => {
      axios.get('/api/search?q=' + encodeURIComponent(search))
        .then(res => setResultados(res.data))
        .catch(() => setResultados(null))
        .finally(() => setLoading(false));
    }, 350);
    return () => clearTimeout(timeout);
  }, [search]);

  // Spotlight: fecha com ESC
  useEffect(() => {
    function onKeyDown(e) { if (e.key === "Escape") setSearchOpen(false); }
    if (searchOpen) {
      window.addEventListener("keydown", onKeyDown);
      return () => window.removeEventListener("keydown", onKeyDown);
    }
  }, [searchOpen]);

  function onBackdropClick(e) {
    if (e.target === e.currentTarget) setSearchOpen(false);
  }

  // Navegação por resultado
  function handleResultClick(tipo, id) {
    setSearchOpen(false);
    if (tipo === "aluno") navigate(`/alunos/${id}`);
    else if (tipo === "paciente") navigate(`/pacientes/${id}`);
    else if (tipo === "disciplina") navigate(`/disciplinas/${id}`);
  }

  const toggleDropdown = () => setDropdownOpen(open => !open);
  const handlePerfil = () => { setDropdownOpen(false); navigate('/perfil'); };
  const handleLogout = () => { setDropdownOpen(false); logout(); navigate('/login', { replace: true }); };

  // Remove o usuário logado da lista de online (se houver)
  const others = onlineUsers.filter(u => u.id !== user?.id);
  const firstThree = others.slice(0, 3);
  const moreCount = others.length > 3 ? others.length - 3 : 0;

  return (
    <header className="fixed top-0 left-0 right-0 h-16 bg-white shadow flex items-center justify-between px-6 z-50">
      <h1 className="text-2xl font-bold text-[#0095DA]">PoliUB Atendimentos</h1>
      <div className="flex items-center space-x-4">
        {/* Botão de pesquisa */}
        <button
          className="p-2 rounded-full hover:bg-gray-100 transition"
          onClick={() => setSearchOpen(true)}
          aria-label="Pesquisar"
        >
          <Search size={22} />
        </button>

        {/* Spotlight minimalista (sem card, centralizado) */}
        {searchOpen && (
          <div
            className="fixed inset-0 z-[999] flex flex-col items-center justify-center bg-black/50"
            onClick={onBackdropClick}
            style={{ minHeight: '100dvh' }}
          >
            <input
              ref={searchInputRef}
              className="w-full max-w-xl text-2xl px-8 py-4 bg-white/90 outline-none shadow-2xl rounded-full placeholder-gray-400 border-0 focus:ring-2 focus:ring-[#0095DA] mb-5"
              style={{ transition: 'box-shadow .1s', fontWeight: 500 }}
              placeholder="Digite para pesquisar em todo o sistema..."
              autoFocus
              value={search}
              onChange={e => setSearch(e.target.value)}
              onClick={e => e.stopPropagation()}
            />
            <div
              className="w-full max-w-xl bg-white/90 rounded-xl overflow-y-auto"
              style={{
                maxHeight: '40vh',
                boxShadow: '0 8px 32px 0 rgba(0,0,0,0.15)'
              }}
              onClick={e => e.stopPropagation()}
            >
              {loading && <div className="p-6 text-gray-400 text-center">Pesquisando...</div>}
              {resultados && (
                <div className="px-1 pt-1 pb-3">
                  {resultados.alunos?.length > 0 && (
                    <div>
                      <div className="font-bold text-blue-700 px-5 pt-2 pb-1">Alunos</div>
                      <ul>
                        {resultados.alunos.map(a => (
                          <li
                            key={"aluno-" + a.id}
                            className="px-5 py-2 cursor-pointer hover:bg-blue-50 rounded flex items-center gap-2"
                            onClick={() => handleResultClick("aluno", a.id)}
                          >
                            <span className="font-semibold">{a.nome}</span>
                            <span className="text-xs text-gray-500">({a.usuario})</span>
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                  {resultados.pacientes?.length > 0 && (
                    <div className="mt-1">
                      <div className="font-bold text-green-700 px-5 pt-2 pb-1">Pacientes</div>
                      <ul>
                        {resultados.pacientes.map(p => (
                          <li
                            key={"pac-" + p.id}
                            className="px-5 py-2 cursor-pointer hover:bg-green-50 rounded flex items-center gap-2"
                            onClick={() => handleResultClick("paciente", p.id)}
                          >
                            <span className="font-semibold">{p.nome}</span>
                            <span className="text-xs text-gray-500">{p.cpf}</span>
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                  {resultados.disciplinas?.length > 0 && (
                    <div className="mt-1">
                      <div className="font-bold text-orange-700 px-5 pt-2 pb-1">Disciplinas</div>
                      <ul>
                        {resultados.disciplinas.map(d => (
                          <li
                            key={"disc-" + d.id}
                            className="px-5 py-2 cursor-pointer hover:bg-orange-50 rounded flex items-center gap-2"
                            onClick={() => handleResultClick("disciplina", d.id)}
                          >
                            <span className="font-semibold">{d.nome}</span>
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                  {resultados.alunos?.length === 0 && resultados.pacientes?.length === 0 && resultados.disciplinas?.length === 0 && (
                    <div className="text-gray-500 text-center py-8">Nenhum resultado encontrado.</div>
                  )}
                </div>
              )}
            </div>
          </div>
        )}

        {/* Avatares online */}
        <div className="flex items-center space-x-2 relative">
          {user && (
            <img
              src={
                user.avatar_url ||
                `https://ui-avatars.com/api/?name=${encodeURIComponent(user.nome)}&background=ccc`
              }
              alt={user.nome}
              title={user.nome}
              className="w-8 h-8 rounded-full"
              style={{ border: `2px solid ${BORDER_COLORS[0]}` }}
            />
          )}
          {firstThree.map((u, i) => (
            <img
              key={u.id}
              src={
                u.avatar_url ||
                `https://ui-avatars.com/api/?name=${encodeURIComponent(u.nome)}&background=ccc`
              }
              alt={u.nome}
              title={u.nome}
              className="w-8 h-8 rounded-full"
              style={{ border: `2px solid ${BORDER_COLORS[(i + 1) % BORDER_COLORS.length]}` }}
            />
          ))}
          {moreCount > 0 && (
            <button
              className="w-8 h-8 rounded-full bg-gray-100 border border-gray-300 text-xs font-bold flex items-center justify-center hover:bg-gray-200"
              onClick={() => setShowAllOnline(val => !val)}
              title="Mostrar todos online"
              style={{ minWidth: '2rem' }}
            >+{moreCount}</button>
          )}

          {showAllOnline && (
            <div
              ref={popoverRef}
              className="absolute right-0 mt-4 bg-white border rounded-lg shadow-lg p-4 z-50 w-64 max-w-[95vw] md:w-72 flex flex-col gap-2 max-h-72 overflow-y-auto"
              style={{
                top: '2.2rem',
                right: 0,
                minWidth: '210px'
              }}
            >
              {others.map((u, i) => (
                <div key={u.id} className="flex items-center gap-3 py-1">
                  <img
                    src={
                      u.avatar_url ||
                      `https://ui-avatars.com/api/?name=${encodeURIComponent(u.nome)}&background=ccc`
                    }
                    alt={u.nome}
                    className="w-8 h-8 rounded-full"
                    style={{
                      border: `2px solid ${BORDER_COLORS[(i + 1) % BORDER_COLORS.length]}`
                    }}
                  />
                  <span className="text-gray-800 text-sm break-all">{u.nome}</span>
                </div>
              ))}
              <button
                className="mt-3 px-3 py-1 bg-gray-200 rounded text-sm font-semibold hover:bg-gray-300"
                onClick={() => setShowAllOnline(false)}
              >
                Fechar
              </button>
            </div>
          )}
        </div>

        {/* Botão e dropdown de perfil */}
        <div ref={wrapperRef} className="relative">
          <button
            onClick={toggleDropdown}
            className="rounded-full focus:outline-none focus:ring-2 focus:ring-blue-400"
          >
            <AvatarIcon />
          </button>
          {dropdownOpen && (
            <ul className="absolute right-0 mt-2 w-48 bg-white border border-gray-200 rounded-lg shadow-lg z-50">
              <li className="px-4 py-2 text-gray-700 font-medium border-b border-gray-100">
                {user?.nome || 'Usuário'}
              </li>
              <li>
                <button
                  onClick={handlePerfil}
                  className="w-full text-left px-4 py-2 hover:bg-gray-100 text-gray-700"
                >
                  Meu Perfil
                </button>
              </li>
              <li>
                <button
                  onClick={handleLogout}
                  className="w-full text-left px-4 py-2 hover:bg-gray-100 text-red-600"
                >
                  Sair
                </button>
              </li>
            </ul>
          )}
        </div>
      </div>
    </header>
  );
}
